import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { LayoutDashboard, Calendar, Users, LogOut, Activity, User, Heart, CheckCircle, Clock, MapPin, FileText } from 'lucide-react';

const statusColors = { pending: '#d97706', assigned: '#1d4ed8', active: '#16a34a', completed: '#0d9488', cancelled: '#e11d48' };
const careIcon = { elderly: '👴', maternity: '🤱', childcare: '👶' };

export default function CaregiverDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [updateMsg, setUpdateMsg] = useState('');
  const [selectedBooking, setSelectedBooking] = useState(null);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [bRes, pRes] = await Promise.all([axios.get('/bookings'), axios.get('/caregivers/me').catch(() => ({ data: null }))]);
      setBookings(bRes.data);
      setProfile(pRes.data);
    } catch { toast.error('Failed to load data'); }
    finally { setLoading(false); }
  };

  const updateStatus = async (id, status) => {
    try {
      await axios.patch(`/bookings/${id}/status`, { status });
      toast.success('Status updated');
      fetchData();
    } catch { toast.error('Failed to update status'); }
  };

  const addHealthUpdate = async (id) => {
    if (!updateMsg.trim()) return;
    try {
      await axios.post(`/bookings/${id}/health-update`, { message: updateMsg });
      toast.success('Health update sent to family');
      setUpdateMsg('');
      fetchData();
    } catch { toast.error('Failed to send update'); }
  };

  const assigned = bookings.filter(b => b.status === 'assigned');
  const active = bookings.filter(b => b.status === 'active');
  const completed = bookings.filter(b => b.status === 'completed');

  const navItems = [
    { id: 'overview', icon: LayoutDashboard, label: 'Overview' },
    { id: 'patients', icon: Users, label: 'My Patients' },
    { id: 'schedule', icon: Calendar, label: 'Schedule' },
    { id: 'updates', icon: Activity, label: 'Care Logs' },
    { id: 'profile', icon: User, label: 'My Profile' },
  ];

  return (
    <div className="dashboard-layout">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18} color="#0d9488" style={{ display: 'inline', marginRight: 6 }} />
          Prana Solutions
        </div>
        <nav className="sidebar-nav">
          {navItems.map(item => (
            <div key={item.id} className={`sidebar-item ${activeTab === item.id ? 'active' : ''}`} onClick={() => setActiveTab(item.id)}>
              <item.icon size={18} /> {item.label}
            </div>
          ))}
        </nav>
        <div style={{ marginTop: 'auto', paddingTop: 16, borderTop: '1px solid #f3f4f6' }}>
          <div style={{ padding: '12px 14px', marginBottom: 8 }}>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#111827' }}>{user?.name}</div>
            <span className="badge badge-teal" style={{ fontSize: 11, marginTop: 4 }}>Caregiver</span>
          </div>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18} /> Sign Out
          </div>
        </div>
      </aside>

      <main className="main-content">
        {/* Overview */}
        {activeTab === 'overview' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">Welcome, {user?.name?.split(' ')[0]}! 🌟</h1>
              <p className="page-sub">Your caregiver dashboard — manage patients and care logs.</p>
            </div>

            <div className="stats-grid">
              {[
                { label: 'Total Patients', value: bookings.length, icon: Users, color: '#e0f2fe', iconColor: '#0284c7' },
                { label: 'Assigned', value: assigned.length, icon: Calendar, color: '#fef3c7', iconColor: '#d97706' },
                { label: 'Active Care', value: active.length, icon: Activity, color: '#dcfce7', iconColor: '#16a34a' },
                { label: 'Completed', value: completed.length, icon: CheckCircle, color: '#ccfbf1', iconColor: '#0f766e' },
              ].map(s => (
                <div key={s.label} className="card stat-card">
                  <div className="stat-icon" style={{ background: s.color }}><s.icon size={20} color={s.iconColor} /></div>
                  <div className="stat-value">{s.value}</div>
                  <div className="stat-label">{s.label}</div>
                </div>
              ))}
            </div>

            {/* Active patients */}
            <h2 className="section-title">Active Patients</h2>
            {loading ? <div style={{ textAlign: 'center', padding: 40 }}><div className="spinner" style={{ margin: '0 auto' }} /></div>
              : [...assigned, ...active].length === 0 ? (
                <div className="empty-state"><Users size={48} /><h3>No active patients</h3><p>You have no currently assigned patients.</p></div>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                  {[...assigned, ...active].map(b => (
                    <PatientCard key={b._id} booking={b} onStatusUpdate={updateStatus} onSelect={() => setSelectedBooking(b)} />
                  ))}
                </div>
              )}
          </div>
        )}

        {/* Patients tab */}
        {activeTab === 'patients' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">My Patients</h1>
              <p className="page-sub">{bookings.length} total patient{bookings.length !== 1 ? 's' : ''}</p>
            </div>
            {bookings.length === 0 ? (
              <div className="empty-state"><Users size={48} /><h3>No patients yet</h3><p>Your assigned patients will appear here.</p></div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                {bookings.map(b => (
                  <PatientCard key={b._id} booking={b} onStatusUpdate={updateStatus} expanded
                    onAddUpdate={(id) => { setSelectedBooking(b); setActiveTab('updates'); }} />
                ))}
              </div>
            )}
          </div>
        )}

        {/* Schedule tab */}
        {activeTab === 'schedule' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">My Schedule</h1>
              <p className="page-sub">Your upcoming care appointments</p>
            </div>
            {bookings.filter(b => b.status !== 'completed' && b.status !== 'cancelled').length === 0 ? (
              <div className="empty-state"><Calendar size={48} /><h3>No scheduled appointments</h3></div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
                {bookings.filter(b => !['completed', 'cancelled'].includes(b.status)).map(b => (
                  <div key={b._id} className="card" style={{ padding: 24 }}>
                    <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start' }}>
                      <div style={{ fontSize: 32 }}>{careIcon[b.careType]}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 700, fontSize: 16, color: '#111827', marginBottom: 6 }}>{b.patient?.name}</div>
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 16, fontSize: 13, color: '#6b7280' }}>
                          <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}><Clock size={13} /> {b.schedule?.timeSlot}</span>
                          <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}><Calendar size={13} /> {b.schedule?.startDate ? new Date(b.schedule.startDate).toLocaleDateString('en-IN') : 'TBD'}</span>
                          <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}><MapPin size={13} /> {b.location?.city}</span>
                        </div>
                        <div style={{ marginTop: 10 }}>
                          <span style={{ fontSize: 12, fontWeight: 600, padding: '4px 12px', borderRadius: 20, background: '#f0fdfa', color: '#0f766e' }}>{b.schedule?.duration}</span>
                        </div>
                        {b.additionalNotes && (
                          <div style={{ marginTop: 10, padding: '10px 14px', background: '#fefce8', borderRadius: 10, fontSize: 13, color: '#92400e', borderLeft: '3px solid #fcd34d' }}>
                            <strong>Note:</strong> {b.additionalNotes}
                          </div>
                        )}
                      </div>
                      <span style={{ fontSize: 11, fontWeight: 700, padding: '4px 12px', borderRadius: 20, background: '#f0fdfa', color: statusColors[b.status] || '#374151', border: `1px solid ${statusColors[b.status]}30` }}>
                        {b.status?.toUpperCase()}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Care Logs / Updates tab */}
        {activeTab === 'updates' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">Care Logs</h1>
              <p className="page-sub">Send health updates to families</p>
            </div>
            {bookings.filter(b => ['assigned', 'active'].includes(b.status)).map(b => (
              <div key={b._id} className="card" style={{ padding: 28, marginBottom: 20 }}>
                <div style={{ display: 'flex', gap: 14, alignItems: 'center', marginBottom: 20 }}>
                  <div style={{ fontSize: 28 }}>{careIcon[b.careType]}</div>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 16, color: '#111827' }}>{b.patient?.name}</div>
                    <div style={{ fontSize: 13, color: '#6b7280' }}>{b.careType} · {b.location?.city}</div>
                  </div>
                </div>
                {/* Past updates */}
                {(b.healthUpdates || []).length > 0 && (
                  <div style={{ marginBottom: 20 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: '#6b7280', marginBottom: 10, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Previous Updates</div>
                    {b.healthUpdates.slice(-3).map((u, i) => (
                      <div key={i} style={{ padding: '10px 14px', background: '#f8fafc', borderRadius: 10, marginBottom: 8, fontSize: 13 }}>
                        <div style={{ color: '#9ca3af', marginBottom: 3 }}>{new Date(u.timestamp).toLocaleString('en-IN')}</div>
                        <div style={{ color: '#374151' }}>{u.message}</div>
                      </div>
                    ))}
                  </div>
                )}
                {/* Add update */}
                <div>
                  <div style={{ fontSize: 13, fontWeight: 600, color: '#6b7280', marginBottom: 8, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Add Health Update</div>
                  <textarea className="form-textarea" placeholder={`Update for ${b.patient?.name}'s family...`} value={selectedBooking?._id === b._id ? updateMsg : ''}
                    onChange={e => { setSelectedBooking(b); setUpdateMsg(e.target.value); }} style={{ minHeight: 80, marginBottom: 10 }} />
                  <button className="btn btn-primary btn-sm" onClick={() => addHealthUpdate(b._id)} disabled={!updateMsg.trim() || selectedBooking?._id !== b._id}>
                    <Activity size={14} /> Send Update
                  </button>
                </div>
              </div>
            ))}
            {bookings.filter(b => ['assigned', 'active'].includes(b.status)).length === 0 && (
              <div className="empty-state"><FileText size={48} /><h3>No active patients</h3><p>Health logs for active patients appear here.</p></div>
            )}
          </div>
        )}

        {/* Profile */}
        {activeTab === 'profile' && (
          <div>
            <div className="page-header">
              <h1 className="page-title">My Profile</h1>
              <p className="page-sub">Your caregiver profile and information</p>
            </div>
            <div className="card" style={{ padding: 32, maxWidth: 540 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 20, marginBottom: 28 }}>
                <div style={{ width: 64, height: 64, borderRadius: '50%', background: '#ccfbf1', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24, fontWeight: 700, color: '#0f766e' }}>
                  {user?.name?.charAt(0)}
                </div>
                <div>
                  <div style={{ fontSize: 20, fontWeight: 700, color: '#111827' }}>{user?.name}</div>
                  <div style={{ fontSize: 14, color: '#6b7280', marginBottom: 6 }}>{user?.email}</div>
                  <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                    <span className="badge badge-teal">Caregiver</span>
                    {profile?.isVerified && <span className="badge badge-green">✓ Verified</span>}
                  </div>
                </div>
              </div>
              {profile && (
                <>
                  <div style={{ marginBottom: 20 }}>
                    <div style={{ fontSize: 12, fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 10 }}>Specializations</div>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                      {profile.specializations?.map(s => <span key={s} className="badge badge-teal">{s}</span>)}
                    </div>
                  </div>
                  {[
                    { label: 'Experience', value: `${profile.experience} year${profile.experience !== 1 ? 's' : ''}` },
                    { label: 'Rating', value: `${profile.rating}/5 ⭐ (${profile.totalReviews} reviews)` },
                    { label: 'Location', value: profile.location || 'Not set' },
                    { label: 'Bio', value: profile.bio || 'Not set' },
                  ].map(f => (
                    <div key={f.label} style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 0', borderBottom: '1px solid #f3f4f6', fontSize: 14 }}>
                      <span style={{ color: '#9ca3af', fontWeight: 600 }}>{f.label}</span>
                      <span style={{ color: '#111827', fontWeight: 500, maxWidth: '60%', textAlign: 'right' }}>{f.value}</span>
                    </div>
                  ))}
                </>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

function PatientCard({ booking: b, onStatusUpdate, expanded, onAddUpdate }) {
  const careIcon = { elderly: '👴', maternity: '🤱', childcare: '👶' };
  const statusColors = { pending: '#d97706', assigned: '#1d4ed8', active: '#16a34a', completed: '#0d9488', cancelled: '#e11d48' };
  return (
    <div className="card" style={{ padding: 24 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12 }}>
        <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start' }}>
          <div style={{ fontSize: 32 }}>{careIcon[b.careType]}</div>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
              <span style={{ fontSize: 16, fontWeight: 700, color: '#111827' }}>{b.patient?.name}</span>
              <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 10px', borderRadius: 20, background: `${statusColors[b.status]}15`, color: statusColors[b.status] }}>{b.status?.toUpperCase()}</span>
            </div>
            <div style={{ fontSize: 13, color: '#6b7280' }}>{b.careType} · Age {b.patient?.age} · {b.patient?.gender}</div>
            {b.patient?.medicalConditions && (
              <div style={{ fontSize: 12, color: '#d97706', marginTop: 4, fontWeight: 500 }}>⚕️ {b.patient.medicalConditions}</div>
            )}
            {expanded && (
              <div style={{ marginTop: 10, display: 'flex', flexWrap: 'wrap', gap: 12, fontSize: 13, color: '#6b7280' }}>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}><Clock size={13} /> {b.schedule?.timeSlot}</span>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}><MapPin size={13} /> {b.location?.address}</span>
              </div>
            )}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {b.status === 'assigned' && (
            <button className="btn btn-primary btn-sm" onClick={() => onStatusUpdate(b._id, 'active')}>
              <CheckCircle size={14} /> Mark Active
            </button>
          )}
          {b.status === 'active' && (
            <button className="btn btn-sm" style={{ background: '#dcfce7', color: '#16a34a', border: 'none', cursor: 'pointer' }} onClick={() => onStatusUpdate(b._id, 'completed')}>
              <CheckCircle size={14} /> Complete
            </button>
          )}
          {onAddUpdate && ['assigned', 'active'].includes(b.status) && (
            <button className="btn btn-ghost btn-sm" onClick={() => onAddUpdate(b._id)}>
              <Activity size={14} /> Add Update
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
